import React, { useState } from "react";
import searchIcon from "./../../media/search-icon.png";
import { Cards } from "../data/Cards";
import { Link } from "react-router-dom"


function Navbar() {
    const [sResults, setSResults] = useState(false)
    const [search, setSearch] = useState(false)
    const handleSearch = (sm) => {
        setSearch(sm);
        setSResults(
            Cards.filter((elem) => elem.title.toLowerCase().includes(sm.toLowerCase())) 
        );    
    };
    return (
        <nav className="navbar">
                <a href="" className="navbar__logo"></a>
            <Link to="/" className="navbar__link">
                Главная
            </Link>
            <Link to="/catalog" className="navbar__link">
                Каталог
            </Link>
            <Link to="/korzina" className="navbar__link">
                Избранные
            </Link>
            <Link to="/phones" className="navbar__link">
                Смартфоны
            </Link>
            <Link to="/bicycles" className="navbar__link">
                Велосипеды
            </Link>
            <div className="navbar__search">
                <input type="text" placeholder="Я хочу найти..." onChange={(e) => handleSearch(e.target.value)} />
                <img src={searchIcon} alt="search" />
                {sResults && search.length > 0 ? (
                    <ul className="smart__results">
                        {sResults.map((elem) => {
                            return (
                                <li key={"searchId" + elem.id}>
                                    <Link to={"/p/" + elem.id}>{elem.title}</Link>
                                </li>
                            )
                        })}
                    </ul>
                ) : null}
            </div>
        </nav>
    )
}

export default Navbar
